            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="مثال: الکترولیز آب، یا واکنش آلومینیوم با اکسید کروم..."
            className="flex-1 p-3 border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder:text-gray-400"
            disabled={isLoading}
          />
          <button
            type="submit"
            disabled={isLoading || !input.trim()}
            className={`
              whitespace-nowrap px-6 py-3 rounded-lg font-bold text-white shadow-md transition-all flex items-center justify-center gap-2
              ${isLoading || !input.trim()
                ? 'bg-indigo-300 cursor-not-allowed'
                : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-lg active:scale-95'
              }
            `}
          >
            {isLoading ? (
              <span className="animate-spin h-5 w-5 border-2 border-white border-t-transparent rounded-full"></span>
            ) : (
              <>
                <span>⛏️</span>
                استخراج عنصر
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { Header } from './components/Header';
import { InputSection } from './components/InputSection';
import { ElementSelection } from './components/ElementSelection';
import { ExtractionLab } from './components/ExtractionLab';
import { ResultDisplay } from './components/ResultDisplay';
import { analyzeChemicalQuery } from './services/geminiService';

const App: React.FC = () => {
  const [result, setResult] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleAnalyze = async (query: string) => {
    setIsLoading(true);
    setError(null);
    setResult(null);

    try {
      const data = await analyzeChemicalQuery(query);
      setResult(data);
    } catch (err) {
      if (err instanceof Error) {
        setError(err.message);
      } else {
        setError("خطای ناشناخته رخ داده است.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <Header />

      <main className="max-w-5xl mx-auto px-4 mt-8 space-y-8">
        {/* Intro Card */}
        <div className="bg-blue-50 border-r-4 border-blue-600 p-4 rounded-md shadow-sm">
          <p className="text-blue-900 font-medium leading-7">
            به **ChemMaster Pro** خوش آمدید. نام عنصر، ترکیب یا معادله واکنش مورد نظر خود را وارد کنید تا تحلیل جامع دکترا شامل **شبیه‌سازی گام‌به‌گام مراحل واکنش**، ایمنی و امکان‌سنجی صنعتی در افغانستان را دریافت کنید.
          </p>
        </div>

        <InputSection onAnalyze={handleAnalyze} isLoading={isLoading} />

        <ElementSelection onAnalyze={handleAnalyze} isLoading={isLoading} />

        <ExtractionLab onAnalyze={handleAnalyze} isLoading={isLoading} />

        {error && (
          <div className="bg-red-50 border-r-4 border-red-500 text-red-700 p-4 rounded-md shadow-sm animate-pulse">
            <p className="font-bold mb-1">خطا در پردازش</p>
            <p>{error}</p>
          </div>
        )}

        <ResultDisplay result={result} />
      </main>

      <footer className="mt-20 text-center text-gray-400 text-sm py-6">
        <p>ChemMaster Pro &copy; {new Date().getFullYear()} - Powered by Gemini 2.5 Flash</p>
      </footer>
    </div>
  );
};

export default App;
